{"code":"import json

def build_query(tickers):
    parts = []
    for t in tickers:
        parts.append("SELECT '{}' AS symbol, MAX(\"Adj Close\") AS max_adj_close_2015 FROM \"{}\" WHERE Date >= '2015-01-01' AND Date <= '2015-12-31'".format(t, t))
